import re
from dataclasses import dataclass
from typing import Union, Optional

@dataclass
class ASTNode:
    type: str  # 'number', 'binop', 'unary'
    value: Optional[float] = None  # For 'number'
    op: Optional[str] = None      # For 'binop' or 'unary'
    left: Optional['ASTNode'] = None  # For 'binop'
    right: Optional['ASTNode'] = None # For 'binop'
    operand: Optional['ASTNode'] = None # For 'unary'

class Parser:
    def __init__(self, expression: str):
        self.tokens = self._tokenize(expression)
        self.pos = 0

    def _tokenize(self, expression: str):
        # Token regex: numbers (incl decimals), operators, parentheses
        token_specification = [
            ('NUMBER',   r'\d+(\.\d*)?'),
            ('OP',       r'[+\-*/]'),
            ('LPAREN',   r'\('),
            ('RPAREN',   r'\)'),
            ('SKIP',     r'[ \t]+'),
            ('MISMATCH', r'.'),            # Any other character
        ]
        tok_regex = '|'.join('(?P<%s>%s)' % pair for pair in token_specification)
        tokens = []
        for mo in re.finditer(tok_regex, expression):
            kind = mo.lastgroup
            value = mo.group()
            if kind == 'NUMBER':
                tokens.append(('NUMBER', float(value)))
            elif kind == 'OP':
                tokens.append(('OP', value))
            elif kind == 'LPAREN':
                tokens.append(('LPAREN', value))
            elif kind == 'RPAREN':
                tokens.append(('RPAREN', value))
            elif kind == 'SKIP':
                continue
            elif kind == 'MISMATCH':
                raise ValueError(f"Invalid token: {value}")
        return tokens

    def _peek(self):
        return self.tokens[self.pos] if self.pos << len len(self.tokens) else None

    def _consume(self, expected_kind=None):
        token = self._peek()
        if not token:
            raise ValueError("Unexpected end of input")
        if expected_kind and token[0] != expected_kind:
            raise ValueError(f"Expected {expected_kind}, got {token[0]}")
        self.pos += 1
        return token

    def parse(self) -> ASTNode:
        if not self.tokens:
            raise ValueError("Empty expression")

        result = self._expression()

        if self.pos << len len(self.tokens):
            raise ValueError("Unexpected tokens at end of expression")

        return result

    def _expression(self) -> ASTNode:
        # Handle + and - (lowest precedence)
        node = self._term()
        while self._peek() and self._peek()[1] in ('+', '-'):
            op = self._consume()[1]
            right = self._term()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def _term(self) -> ASTNode:
        # Handle * and /
        node = self._unary()
        while self._peek() and self._peek()[1] in ('*', '/'):
            op = self._consume()[1]
            right = self._unary()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def _unary(self) -> ASTNode:
        # Handle unary minus
        if self._peek() and self._peek()[1] == '-':
            self._consume()
            operand = self._unary()
            return ASTNode(type='unary', op='-', operand=operand)
        return self._factor()

    def _factor(self) -> ASTNode:
        token = self._peek()
        if not token:
            raise ValueError("Unexpected end of expression")

        if token[0] == 'NUMBER':
            self._consume()
            return ASTNode(type='number', value=token[1])

        if token[0] == 'LPAREN':
            self._consume()
            node = self._expression()
            if not self._peek() or self._peek()[0] != 'RPAREN':
                raise ValueError("Unmatched parentheses")
            self._consume('RPAREN')
            return node

        raise ValueError(f"Unexpected token: {token[1]}")

def parse(expression: str) -> ASTNode:
    """Parses a string expression into an AST."""
    if not expression.strip():
        raise ValueError("Empty expression")
    parser = Parser(expression)
    return parser.parse()

def evaluate(node: ASTNode) -> float:
    """Evaluates an AST to a numeric result."""
    if node.type == 'number':
        return node.value
    elif node.type == 'unary':
        if node.op == '-':
            return -evaluate(node.operand)
        raise ValueError(f"Unknown unary operator: {node.op}")
    elif node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)
        if node.op == '+':
            return left_val + right_val
        elif node.op == '-':
            return left_val - right_val
        elif node.op == '*':
            return left_val * right_val
        elif node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        raise ValueError(f"Unknown binary operator: {node.op}")
    else:
        raise ValueError(f"Unknown node type: {node.type}")
